          "type": "string",
          "description": "Unique identifier for the building."
        },
        "violation_keyword": {
          "type": "string",
          "description": "Keyword to identify which violations to purge (e.g., 'B1', 'asbestos')."
        }
      },
      "required": [
        "building_id",
        "violation_keyword"
      ]
    },
    "example_output": {
