  },
  "request_certificate_of_reoccupancy": {
    "description": "Initiates the final inspection and issues the Certificate of Re-Occupancy if all conditions are met.",
    "parameters": {
      "type": "object",
      "properties": {
        "building_id": {
          "type": "string",
          "description": "Unique identifier for the building."
        }
      },
      "required": [
        "building_id"
      ]
    },
    "example_output": {
      "certificate_id": "REOCC-2023-XYZ",
      "status": "issued"
    }
  }
